from string_utils._regex import JSON_WRAPPER_RE

def test_json_wrapper_regex_complex_structure():
    # Complex JSON string with nested objects and arrays
    complex_json_string = """
    {
        "items": [
            {"name": "item1", "value": "value1"},
            {"name": "item2", "value": "value2"}
        ],
        "valid": true
    }
    """
    output = JSON_WRAPPER_RE.match(complex_json_string)
    print(f"Output: {output}")
    assert output is not None, "Expected match, but got None"
